    var currency = "";
    for (var ci = 0; ci < 3; ci++) {
      var ch = parseInt(clean.slice(ci * 2, ci * 2 + 2), 16);
      currency += ch >= 0x20 && ch <= 0x7E ? String.fromCharCode(ch) : "?";
    }
