      lac1Input.type = "text";
      lac1Input.className = "saip-wizard-text saip-wizard-text--mono";
      lac1Input.maxLength = 4;
      lac1Input.value = ((lac1 & 0xFFFF)).toString(16).toUpperCase().padStart(4, "0");
