  // 3GPP TS 31.102 §4.2.28 — EF.SMSS (transparent 2 B):
  // byte 1 bit 0: Memory Capacity Exceeded flag
  // byte 2: last used record index.
  var _SAIP_WIZARD_SMSS = {
    title: "EF.SMSS wizard",
    spec: "3GPP TS 31.102 §4.2.28 — SMS Status (MCE flag + last record).",
    render: function (host, currentHex, applyFn) {
      var bytes = _saipHexToBytes(currentHex);
      while (bytes.length < 2) bytes.push(0x00);
      var mce = (bytes[0] & 0x01) !== 0;
      var lastRec = bytes[1] & 0xFF;

      var mceCb = document.createElement("input");
      mceCb.type = "checkbox";
      mceCb.checked = mce;
      _saipWizardRow(host, "MCE flag", mceCb, "Memory Capacity Exceeded.");

      var recInput = document.createElement("input");
      recInput.type = "number";
      recInput.className = "saip-wizard-text";
      recInput.min = "0";
      recInput.max = "255";
      recInput.value = String(lastRec);
      _saipWizardRow(host, "Last used record", recInput,
        "0 means no record written yet.");

      _saipWizardApplyButton(host, "Apply SMSS", function () {
        var r = parseInt(recInput.value, 10);
        if (!Number.isFinite(r) || r < 0 || r > 0xFF) {
          throw new Error("Last record must be 0..255.");
        }
        return { hex: _saipBytesToHex([mceCb.checked ? 0x01 : 0x00, r & 0xFF]) };
      }, applyFn);
    },
  };

  var _SAIP_RECORD_WIZARDS = {
    "ef-msisdn": _saipBuildDiallingNumberWizard("MSISDN",
      "3GPP TS 31.102 §4.2.26 — MSISDN record (alpha + dialling number)."),
    "ef-adn":    _saipBuildDiallingNumberWizard("ADN",
      "3GPP TS 31.102 §4.4.2.3 — Abbreviated Dialling Numbers."),
    "ef-fdn":    _saipBuildDiallingNumberWizard("FDN",
      "3GPP TS 31.102 §4.4.2.3 — Fixed Dialling Numbers."),
    "ef-sdn":    _saipBuildDiallingNumberWizard("SDN",
      "3GPP TS 31.102 §4.4.2.3 — Service Dialling Numbers."),
    "ef-bdn":    _saipBuildDiallingNumberWizard("BDN",
      "3GPP TS 31.102 §4.4.2.3 — Barred Dialling Numbers."),
    "ef-mbdn":   _saipBuildDiallingNumberWizard("MBDN",
      "3GPP TS 31.102 §4.2.60 — Mailbox Dialling Numbers (ADN-shaped)."),
    "ef-ecc":    _SAIP_RECORD_WIZARD_ECC,
    "ef-impu":   _SAIP_RECORD_WIZARD_IMPU,
    "ef-opl":    _SAIP_RECORD_WIZARD_OPL,
    "ef-pnn":    _SAIP_RECORD_WIZARD_PNN,
    "ef-mwis":   _SAIP_RECORD_WIZARD_MWIS,
    "ef-mbi":    _SAIP_RECORD_WIZARD_MBI,
    "ef-cfis":   _SAIP_RECORD_WIZARD_CFIS,
    "ef-sms":    _SAIP_RECORD_WIZARD_SMS,
    "ef-smsp":   _SAIP_RECORD_WIZARD_SMSP,
    "ef-smsr":   _SAIP_RECORD_WIZARD_SMSR,
    "ef-ccp1":   _SAIP_RECORD_WIZARD_CCP1,
    "ef-aas":    _saipAlphaLabelRecordWizard("AAS",
      "3GPP TS 31.102 §4.4.3 — Additional Number Alpha String record."),
    "ef-gas":    _saipAlphaLabelRecordWizard("GAS",
      "3GPP TS 31.102 §4.4.3 — Grouping Information Alpha String record."),
    "ef-pbr":    _SAIP_RECORD_WIZARD_PBR,
  };

  // Extend the transparent wizard registry with the second-tier batch.
  _SAIP_WIZARDS["ef-hpplmn"]            = _SAIP_WIZARD_HPPLMN;
  _SAIP_WIZARDS["ef-supi-nai"]          = _SAIP_WIZARD_SUPI_NAI;
  _SAIP_WIZARDS["ef-supinai"]           = _SAIP_WIZARD_SUPI_NAI;
  _SAIP_WIZARDS["ef-routing-indicator"] = _SAIP_WIZARD_ROUTING_INDICATOR;
  _SAIP_WIZARDS["ef-uac-aic"]           = _SAIP_WIZARD_UAC_AIC;
  _SAIP_WIZARDS["ef-keys"]              = _SAIP_WIZARD_KEYS;
  _SAIP_WIZARDS["ef-keysps"]            = _SAIP_WIZARD_KEYSPS;
  _SAIP_WIZARDS["ef-kc"]                = _SAIP_WIZARD_KC;
  _SAIP_WIZARDS["ef-kcgprs"]            = _SAIP_WIZARD_KCGPRS;
  _SAIP_WIZARDS["ef-start-hfn"]         = _SAIP_WIZARD_START_HFN;
  _SAIP_WIZARDS["ef-pcscf"]             = _SAIP_WIZARD_PCSCF;

  // ── Tier-3 transparent wizards ────────────────────────────────

  // 3GPP TS 31.102 §4.2.85 — EF.EHPLMNPI (Equivalent HPLMN
  // Presentation Indication). 1 byte: 0x00 = no indication,
  // 0x01 = display HPLMN, 0x02 = display registered PLMN, others RFU.
  var _SAIP_WIZARD_EHPLMNPI = {
    title: "EF.EHPLMNPI wizard",
    spec: "3GPP TS 31.102 §4.2.85 — Equivalent HPLMN Presentation Indication.",
    render: function (host, currentHex, applyFn) {
      var bytes = _saipHexToBytes(currentHex);
      var initial = (bytes.length > 0) ? bytes[0] & 0xFF : 0x00;
      var sel = document.createElement("select");
      sel.className = "saip-wizard-text";
      [
        { v: 0, l: "0 — No indication" },
        { v: 1, l: "1 — Display HPLMN" },
        { v: 2, l: "2 — Display registered PLMN" },
      ].forEach(function (opt) {
        var o = document.createElement("option");
        o.value = String(opt.v);
        o.textContent = opt.l;
        if (opt.v === initial) o.selected = true;
        sel.appendChild(o);
      });
      _saipWizardRow(host, "Presentation", sel, "TS 31.102 §4.2.85.");
      _saipWizardApplyButton(host, "Apply EHPLMNPI", function () {
        return { hex: _saipHexPad2(parseInt(sel.value, 10) & 0xFF) };
      }, applyFn);
    },
  };

  // 3GPP TS 31.102 §4.2.66 — EF.SPDI (Service Provider Display
  // Information). BER-TLV transparent EF wrapping a PLMN list:
  //   A3 LL                                  outer SPDI tag
  //     80 LL                                  PLMN list tag
  //       <3 B PLMN><3 B PLMN>...
  // Wizard exposes 1..N PLMN slots; on Apply re-wraps with the two
  // BER-TLV headers. EF body is FF-padded to its declared size.
  var _SAIP_WIZARD_SPDI = {
    title: "EF.SPDI wizard",
    spec: "3GPP TS 31.102 §4.2.66 — Service Provider Display Information (BER-TLV PLMN list).",
    render: function (host, currentHex, applyFn) {
      var bytes = _saipHexToBytes(currentHex);
      var totalLen = bytes.length;
      // Decode existing PLMN list — best-effort parse of the
      // A3 → 80 → list-of-3 nesting.
      var plmnBytes = [];
      if (bytes.length >= 4 && bytes[0] === 0xA3) {
        var outerLen = bytes[1] & 0xFF;
        if (bytes[2] === 0x80) {
          var innerLen = bytes[3] & 0xFF;
          var end = Math.min(4 + innerLen, bytes.length, 4 + outerLen);
          plmnBytes = bytes.slice(4, end);
        }
      }
      var slotCount = Math.max(4, Math.floor(plmnBytes.length / 3) || 4);
      // Bound the slot count so a corrupt header doesn't blow up the form.
      slotCount = Math.min(slotCount, Math.max(4, Math.floor((totalLen - 4) / 3)));
      if (!Number.isFinite(slotCount) || slotCount < 1) slotCount = 4;

      var initial = [];
      for (var i = 0; i < slotCount; i++) {
        var s = plmnBytes.slice(i * 3, i * 3 + 3);
        var d = (s.length === 3) ? _saipPlmnDecode(s) : null;
        initial.push(d ? { mcc: d.mcc, mnc: d.mnc } : { mcc: "", mnc: "" });
      }

      var rows = [];
      for (var k = 0; k < slotCount; k++) {
        var row = document.createElement("div");
        row.className = "saip-wizard-plmn-row";
        var label = document.createElement("span");
        label.className = "saip-wizard-plmn-index";
        label.textContent = "#" + (k + 1);
        var mcc = document.createElement("input");
        mcc.type = "text";
        mcc.className = "saip-wizard-text saip-wizard-text--mcc";
        mcc.placeholder = "MCC";
        mcc.maxLength = 3;
        mcc.value = initial[k].mcc;
        var mnc = document.createElement("input");
        mnc.type = "text";
        mnc.className = "saip-wizard-text saip-wizard-text--mnc";
        mnc.placeholder = "MNC";
        mnc.maxLength = 3;
        mnc.value = initial[k].mnc;
        row.appendChild(label);
        row.appendChild(mcc);
        row.appendChild(mnc);
        host.appendChild(row);
        rows.push({ mcc: mcc, mnc: mnc });
      }

      var preview = document.createElement("code");
      preview.className = "saip-wizard-preview";
      _saipWizardRow(host, "Encoded hex", preview,
        "Outer A3 → inner 80 → PLMN list. EF FF-padded to "
        + totalLen + " B.");

      function compute() {
        var list = [];
        for (var i = 0; i < rows.length; i++) {
          var mcc = rows[i].mcc.value.replace(/\D+/g, "");
          var mnc = rows[i].mnc.value.replace(/\D+/g, "");
          if (mcc === "" && mnc === "") continue;
          var enc = _saipPlmnEncode(mcc, mnc);
          list.push(enc[0], enc[1], enc[2]);
        }
        // Wrap: 80 LL <list>
        var inner = [0x80, list.length].concat(list);
        // Wrap: A3 LL <inner>
        var outer = [0xA3, inner.length].concat(inner);
        if (outer.length > totalLen && totalLen > 0) {
          throw new Error("Encoded SPDI (" + outer.length
            + " B) exceeds EF size (" + totalLen + " B).");
        }
        while (outer.length < totalLen) outer.push(0xFF);
        return outer;
      }
      function refresh() {
        try {
          preview.textContent = _saipBytesToHex(compute());
          preview.classList.remove("saip-wizard-preview--error");
        } catch (err) {
          preview.textContent = String(err && err.message || err);
          preview.classList.add("saip-wizard-preview--error");
        }
      }
      rows.forEach(function (r) {
        r.mcc.addEventListener("input", refresh);
        r.mnc.addEventListener("input", refresh);
      });
      refresh();

      _saipWizardApplyButton(host, "Apply SPDI", function () {
        return { hex: _saipBytesToHex(compute()) };
      }, applyFn);
    },
  };

  // 3GPP TS 31.102 §4.4.11.4 — EF.5GS3GPPLOCI / 5GSN3GPPLOCI.
  // 20-byte transparent EF:
  //   bytes 1-13 : 5G-GUTI
  //                  PLMN (3 B)
  //                  AMF Region ID (1 B)
  //                  AMF Set ID + Pointer (2 B; 10 + 6 bits)
  //                  5G-TMSI (4 B)
  //                  Reserved/padding (3 B)
  //   bytes 14-19: Last visited registered TAI (PLMN 3 B + TAC 3 B)
