        var amfRegion = bytes[3] & 0xFF;
        var amfSetPtr = ((bytes[4] & 0xFF) << 8) | (bytes[5] & 0xFF);
        var amfSet = (amfSetPtr >> 6) & 0x03FF;
        var amfPtr = amfSetPtr & 0x003F;
