        var taiPlmn = _saipPlmnDecode(bytes.slice(13, 16));
        var tacHex = _saipBytesToHex(bytes.slice(16, 19));
        var statusInit = bytes[19] & 0x07;

        var gutiHdr = document.createElement("h6");
        gutiHdr.className = "saip-edit-card-hint";
        gutiHdr.textContent = "5G-GUTI (octets 1-13)";
        host.appendChild(gutiHdr);

        var gpMcc = document.createElement("input");
        gpMcc.type = "text";
        gpMcc.className = "saip-wizard-text saip-wizard-text--mcc";
        gpMcc.placeholder = "MCC";
        gpMcc.maxLength = 3;
        gpMcc.value = gutiPlmn ? gutiPlmn.mcc : "";
        var gpMnc = document.createElement("input");
        gpMnc.type = "text";
        gpMnc.className = "saip-wizard-text saip-wizard-text--mnc";
        gpMnc.placeholder = "MNC";
        gpMnc.maxLength = 3;
        gpMnc.value = gutiPlmn ? gutiPlmn.mnc : "";
        var gpRow = document.createElement("div");
        gpRow.className = "saip-wizard-plmn-row";
        gpRow.appendChild(gpMcc);
        gpRow.appendChild(gpMnc);
        _saipWizardRow(host, "PLMN", gpRow, "Registered PLMN.");

        var regInput = document.createElement("input");
        regInput.type = "text";
        regInput.className = "saip-wizard-text saip-wizard-text--mono";
        regInput.maxLength = 2;
        regInput.value = _saipHexPad2(amfRegion);
        _saipWizardRow(host, "AMF Region ID (1 B)", regInput,
          "Hex byte; identifies the AMF Region within the PLMN.");

        var setInput = document.createElement("input");
        setInput.type = "number";
        setInput.className = "saip-wizard-text";
        setInput.min = "0";
        setInput.max = "1023";
        setInput.value = String(amfSet);
        _saipWizardRow(host, "AMF Set ID (10 bits)", setInput, "0..1023.");

        var ptrInput = document.createElement("input");
        ptrInput.type = "number";
        ptrInput.className = "saip-wizard-text";
        ptrInput.min = "0";
        ptrInput.max = "63";
        ptrInput.value = String(amfPtr);
        _saipWizardRow(host, "AMF Pointer (6 bits)", ptrInput, "0..63.");

        var tmsiInput = document.createElement("input");
        tmsiInput.type = "text";
        tmsiInput.className = "saip-wizard-text saip-wizard-text--mono";
        tmsiInput.maxLength = 8;
        tmsiInput.value = tmsiHex;
        _saipWizardRow(host, "5G-TMSI (4 B)", tmsiInput,
          "8 hex chars; assigned by the AMF.");

